            aWandererK = aWandererK ^ (((RotL64(aIngress, 22U) + RotL64(aOrbiterG, 47U)) + aOrbiterC) + aPhaseCWandererUpdateSaltD[(((31U - aIndex) + 24U)) & S_SALT1]);
            aWandererC = aWandererC + ((RotL64(aCross, 57U) + RotL64(aOrbiterI, 39U)) + aOrbiterK);
