            aOrbiterG = (aOrbiterG + aOrbiterJ) + 0xE66F48C35E98F20CULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterG) ^ 0xFDEFCDAFB733C5E6ULL;
            aOrbiterE = RotL64((aOrbiterE * 0x29A61C556B68186BULL), 27U);
