            aIngress = aOrbiterH ^ RotL64(aOrbiterI, 43U);
            aIngress = aIngress + (aOrbiterC ^ RotL64(aOrbiterG, 29U));
            aIngress = aIngress + (RotL64(aOrbiterB, 4U) ^ aOrbiterE);
            aIngress = aIngress + (aOrbiterF ^ RotL64(aOrbiterK, 21U));
            aIngress = aIngress + (aOrbiterJ ^ RotL64(aOrbiterD, 19U));
            aIngress = aIngress + RotL64(aOrbiterA, 23U);
            aIngress = TwistMix64::DiffuseC((aIngress + aScatter));
            //
            aWandererH = aWandererH + (((RotL64(aPrevious, 27U) + aOrbiterD) + RotL64(aOrbiterB, 5U)) + aPhaseGWandererUpdateSaltA[((aIndex + 20U)) & S_SALT1]);
