            //
            aIngress = (RotL64(aExpandLaneA[((aIndex + 4569U)) & S_BLOCK1], 3U) ^ RotL64(aExpandLaneB[((aIndex + 1507U)) & S_BLOCK1], 19U));
            aIngress ^= (RotL64(aWaterLaneD[((aIndex + 2292U)) & S_BLOCK1], 39U) ^ RotL64(aSnowLaneA[((aIndex + 296U)) & S_BLOCK1], 52U));
